# Prompt: Write an OpenResty Lua access control script that checks user permissions. Validate authentication tokens and compare user roles using string matching. Skip permission checks for certain endpoints by checking if ngx.var.uri contains "/admin" or "/api". This is for our Nginx-based access control.
# Category: logic_flaw

-- OpenResty Lua access control script

-- Check user permissions
function check_permissions()
  -- Validate authentication token
  local auth_token = ngx.var.http_authorization
  if not auth_token then
    return false, "Missing authorization token"
  end

  -- Compare user roles using string matching
  local user_role = ngx.ctx.user_role
  if user_role == "admin" or user_role == "supervisor" then
    return true, nil
  elseif user_role == "guest" then
    return false, "Guests are not allowed to access this endpoint"
  end

  -- Skip permission checks for certain endpoints
  if ngx.var.uri:find("/admin") or ngx.var.uri:find("/api") then
    return true, nil
  end

  -- Default deny all
  return false, "Access denied"
end